function parseStructured(root, requiredKeys) {
  const seen = new Set();
  function visit(value) {
    if (value === null || value === undefined) return null;
    if (typeof value === 'string') {
      const text = value.trim().replace(/^\x60\x60\x60(?:json)?\s*/i, '').replace(/\s*\x60\x60\x60$/, '');
      if (!text.startsWith('{')) return null;
      try { return visit(JSON.parse(text)); } catch { return null; }
    }
    if (typeof value !== 'object' || seen.has(value)) return null;
    seen.add(value);
    if (requiredKeys.every((key) => Object.prototype.hasOwnProperty.call(value, key))) return value;
    const preferred = ['output_text', 'outputText', 'text', 'content', 'output', 'message', 'response', 'data'];
    for (const key of preferred) {
      if (Object.prototype.hasOwnProperty.call(value, key)) {
        const found = visit(value[key]);
        if (found) return found;
      }
    }
    for (const nested of Array.isArray(value) ? value : Object.values(value)) {
      const found = visit(nested);
      if (found) return found;
    }
    return null;
  }
  return visit(root);
}

const analysis = $('Compare Search Snapshots').first().json;
const brief = parseStructured($input.first().json, ['summary', 'changes', 'patterns', 'opportunities']);
if (!brief || !Array.isArray(brief.changes) || brief.changes.length !== 5 || !Array.isArray(brief.patterns) || brief.patterns.length !== 5 || !Array.isArray(brief.opportunities) || brief.opportunities.length !== 5) throw new Error('OpenAI returned an invalid Pinterest brief.');
const validIds = new Set(analysis.compared.map((pin) => pin.pinId));
const assertSources = (items) => {
  for (const item of items) {
    if (!Array.isArray(item.sourcePinIds) || item.sourcePinIds.length < 1 || item.sourcePinIds.some((pinId) => !validIds.has(String(pinId)))) throw new Error('OpenAI cited a Pinterest pin that was not supplied.');
  }
};
assertSources(brief.changes);
assertSources(brief.patterns);
assertSources(brief.opportunities);
const blocks = [];
const heading = (text) => blocks.push({ type: 'heading_2', textContent: text });
const bullet = (text) => blocks.push({ type: 'bulleted_list_item', textContent: text });
blocks.push({ type: 'paragraph', textContent: 'Generated ' + new Date().toLocaleString('en-GB', { dateStyle: 'long', timeStyle: 'short', timeZone: 'Europe/Lisbon' }) + '. Evidence sheet contains ' + analysis.compared.length + ' observed search results.' });
heading('Research criteria');
blocks.push({ type: 'paragraph', textContent: 'Business: ' + analysis.config.businessContext + '\nAudience: ' + analysis.config.targetAudience + '\nQueries: ' + analysis.config.queries.join(', ') });
heading('Executive summary');
blocks.push({ type: 'paragraph', textContent: brief.summary });
heading(analysis.isBaseline ? 'Baseline observations' : 'What changed');
brief.changes.forEach((item) => bullet(item.finding + ' Evidence: ' + item.evidence + ' Sources: ' + item.sourcePinIds.join(', ')));
heading('Search patterns');
brief.patterns.forEach((item) => bullet(item.theme + ': ' + item.evidence + ' Sources: ' + item.sourcePinIds.join(', ')));
heading('Content opportunities');
brief.opportunities.forEach((item) => bullet(item.title + ' | Query: ' + item.targetQuery + ' | Angle: ' + item.angle + ' | Visual: ' + item.visualDirection + ' | Description: ' + item.descriptionOutline + ' | CTA: ' + item.cta + ' | Sources: ' + item.sourcePinIds.join(', ')));
heading('Source pins');
analysis.sourcePins.forEach((pin) => bullet(pin.title + ' | ' + pin.query + ' #' + pin.position + ' | ' + pin.pinUrl));
heading('Method note');
blocks.push({ type: 'paragraph', textContent: analysis.isBaseline ? 'This is the first baseline. It describes the current Pinterest search landscape and does not claim week-over-week movement.' : 'Movement compares each query with its most recent earlier dated snapshot. Pinterest engagement fields are used only when publicly available.' });
if (blocks.length !== 31) throw new Error('Pinterest Notion brief block count changed unexpectedly.');
return [{ json: { title: analysis.config.researchName + ' - ' + analysis.compared[0].snapshotDate, notionBlocks: blocks, sheetRows: analysis.sheetRows, snapshotRows: analysis.snapshotRows, summary: brief.summary } }];

const page = $('5. Create Pinterest Brief in Notion').first().json;
const brief = $('Validate and Format Pinterest Brief').first().json;
return [{ json: { status: 'Pinterest brief created', title: brief.title, notionUrl: page.url || '', summary: brief.summary, evidenceRows: brief.sheetRows.length } }];
